use std::collections::HashMap;

#[derive(Debug, PartialEq, Eq, Hash, Clone)]
struct Permission(String);

struct AccessControlList {
    roles: HashMap<String, Vec<Permission>>,
}

impl AccessControlList {
    fn new() -> Self {
        AccessControlList {
            roles: HashMap::new()
        }
    }

    fn add_role(&mut self, role_name: &str, permissions: Vec<Permission>) {
        self.roles.insert(role_name.to_string(), permissions);
    }

    fn has_permission(&self, user_role: &str, required_perm: &str) -> bool {
        if let Some(permissions) = self.roles.get(user_role) {
            permissions.iter().any(|p| p == &Permission(required_perm.to_string()))
        } else {
            false
        }
    }
}

fn main() {
    let mut acl = AccessControlList::new();
    acl.add_role("Guest", vec![Permission("read_basic".to_string())]);
    acl.add_role("Editor", vec![
        Permission("read_basic".to_string()),
        Permission("write_content".to_string())
    ]);
    acl.add_role("Admin", vec![
        Permission("read_basic".to_string()),
        Permission("write_content".to_string()),
        Permission("admin_view_all".to_string())
    ]);

    let user1_can_write = acl.has_permission(&"Editor".to_string(), &"write_content".to_string());
    println!("Editor can write: {}", user1_can_write);

    let user2_view_all = acl.has_permission(&"Guest".to_string(), &"admin_view_all".to_string());
    println!("Guest can view all: {}", user2_view_all);

    let user3_can_manage = acl.has_permission(&"Admin".to_string(), &"admin_view_all".to_string());
    println!("Admin can manage: {}", user3_can_manage);
}

use std::collections::VecDeque;

struct ProcessControlBlock {
    id: u32,
    status: bool,
}

fn main() {
    let mut queue: VecDeque<ProcessControlBlock> = VecDeque::new();
    queue.push_back(ProcessControlBlock { id: 101, status: true });
    queue.push_back(ProcessControlBlock { id: 205, status: false });
    queue.push_back(ProcessControlBlock { id: 330, status: true });

    let initial_size = queue.len();
    println!("Initialized with {} processes.", initial_size);

    if let Some(mut node) = queue.pop_front() {
        node.status = false;
        queue.push_back(node);
    }

    let mut dropped_count = 0;
    for _ in 0..2 {
        if let Some(index) = queue.iter().position(|p| p.id % 3 == 0)
        {
            println!("Simulating crash: removing process at index {}.", index);
            queue.remove(index);
            dropped_count += 1;
        }
    }

    println!("Finished simulation. Process queue size: {}", queue.len());
    assert!(queue.len() <= initial_size);
}

use std::fs::metadata;
use std::path::{Path, PathBuf};

struct FileStatusChecker {
    base_dir: PathBuf,
}

impl FileStatusChecker {
    fn new(base_dir: PathBuf) -> Self {
        FileStatusChecker { base_dir }
    }

    fn check_all(&self, relative_paths: &[String]) -> Vec<bool> {
        relative_paths.iter().map(|rel_path_str| {
            let full_path = self.base_dir.join(rel_path_str);
            match metadata(&full_path) {
                Ok(_) => true,
                Err(e) => { 
                    if e.kind() == std::io::ErrorKind::NotFound {
                        false
                    } else {
                        panic!("Failed to check file status: {}", e)
                    }
                }
            }
        }).collect()
    }
}

fn main() {
    let current_dir = std::env::current_dir().expect("Could not get current directory");
    let checker = FileStatusChecker::new(current_dir.clone());

    let paths_to_check = vec![
        "src/main.rs".to_string(),
        ".gitignore".to_string(),
        "non_existent_file.tmp".to_string()
    ];

    let statuses = checker.check_all(&paths_to_check);

    for (i, status) in statuses.iter().enumerate() {
        println!("Status for {}: {}", paths_to_check[i], if *status { "exists" } else { "missing" } );
    }
}

use rand::RngCore;

struct OptionParams {
    strike_price: f64,
    time_to_maturity: f64,
    volatility: f64,
    risk_free_rate: f64,
}

fn calculate_payoff(stock_price: f64, strike: f64) -> f64 {
    (stock_price - strike).max(0.0)
}

fn monte_carlo_simulation(params: OptionParams, num_simulations: usize) -> f64 {
    let mut rng = rand::thread_rng();
    let mut sum_payoffs = 0.0;

    for _ in 0..num_simulations {
        let random_walk_factor: f64 = (-params.risk_free_rate - params.volatility) / 2.0 
            + (params.volatility * (2.0 * rng.next_u64() as f64 / std::f64::MAX)) 
            * (params.time_to_maturity.sqrt());

        let final_stock_price: f64 = params.strike_price * random_walk_factor.exp();
        sum_payoffs += calculate_payoff(final_stock_price, params.strike_price);
    }

    sum_payoffs / (params.time_to_maturity.powi(2) as f64 * num_simulations as f64) 
}

use std::collections::{HashSet, HashMap};

struct UserSetIntersectionService {
    // In a real MPC scenario, this would involve complex cryptographic primitives.
    // Here we simulate the set intersection logic for demonstration purposes.
}

impl UserSetIntersectionService {
    fn new() -> Self {
        UserSetIntersectionService {}
    }

    fn find_common_elements(set1: &HashSet<u32>, set2: &HashSet<u32>) -> HashSet<u32> {
        let mut intersection = HashSet::new();
        for element in set1.iter() {
            if set2.contains(element) {
                intersection.insert(*element);
            }
        }
        intersection
    }

    fn demonstrate_mpc_like_logic(set_a: &HashSet<u32>, set_b: &HashSet<u32>) -> HashSet<u32> {
        println!("Simulating secure intersection for two parties...");
